+unsafe fn proto_iter_next(state: &mut ProtoIterState) -> *mut c_void {
+    use std::io::BufRead;
+
+    let reader = match state.reader.as_mut() {
+        Some(r) => r,
+        None => return std::ptr::null_mut(),
+    };
