+            *(ptrs.add(1) as *mut *mut *mut c_char) =
+                state.aliases_ptrs.as_mut_ptr();          // p_aliases
+            *(buf.add(16) as *mut c_int) = proto_num;     // p_proto
+        }
+
+        return buf as *mut c_void;
+    }
